package br.com.pueria.pueria.desenvolvimento.infraestrutura.persistencia;
import br.com.pueria.pueria.desenvolvimento.dominio.*; import org.springframework.stereotype.Repository;
@Repository public class HistoricoRespostaMarcoDesenvolvimentoRepositorioJpa implements HistoricoRespostaMarcoDesenvolvimentoRepositorio { private final HistoricoRespostaMarcoDesenvolvimentoJpaRepository repository; public HistoricoRespostaMarcoDesenvolvimentoRepositorioJpa(HistoricoRespostaMarcoDesenvolvimentoJpaRepository repository){this.repository=repository;} public HistoricoRespostaMarcoDesenvolvimento salvar(HistoricoRespostaMarcoDesenvolvimento h){repository.save(new HistoricoRespostaMarcoDesenvolvimentoJpaEntidade(h));return h;} public java.util.List<HistoricoRespostaMarcoDesenvolvimento> listarPorCrianca(java.util.UUID id){return repository.findByCriancaIdOrderByRegistradoEmAsc(id).stream().map(e->new HistoricoRespostaMarcoDesenvolvimento(e.getId(),e.getCriancaId(),e.getMarcoId(),e.getStatusAnterior(),e.getStatusNovo(),e.getObservacaoAnterior(),e.getObservacaoNova(),e.getModalidade(),e.getRegistradoEm())).toList();} }
